'use client';
import { useRef, useState } from 'react';
import { useKanban } from '@/hooks/useKanban';
import Column from './Column';

export default function Board() {
  const { columns, renameColumn, addCard, deleteCard, moveCard } = useKanban();
  const [dragOverColId, setDragOverColId] = useState<string | null>(null);
  const dragging = useRef<{ cardId: string; fromColId: string } | null>(null);

  function onCardDragStart(cardId: string, fromColId: string) {
    dragging.current = { cardId, fromColId };
  }

  function onDrop(toColId: string, toIndex: number) {
    if (!dragging.current) return;
    const { cardId, fromColId } = dragging.current;
    moveCard(cardId, fromColId, toColId, toIndex);
    dragging.current = null;
    setDragOverColId(null);
  }

  function onDragEnd() {
    dragging.current = null;
    setDragOverColId(null);
  }

  return (
    <div className="flex gap-5 p-6 min-h-full items-start">
      {columns.map(col => (
        <Column
          key={col.id}
          column={col}
          isDragOver={dragOverColId === col.id}
          onRename={name => renameColumn(col.id, name)}
          onAddCard={card => addCard(col.id, card)}
          onDeleteCard={cardId => deleteCard(col.id, cardId)}
          onCardDragStart={cardId => onCardDragStart(cardId, col.id)}
          onColumnDragOver={() => setDragOverColId(col.id)}
          onDrop={toIndex => onDrop(col.id, toIndex)}
          onDragEnd={onDragEnd}
        />
      ))}
    </div>
  );
}
